+/// Result of a staleness check between JSONL and DB.
+#[derive(Debug, Clone, Copy)]
+pub struct StalenessCheck {
+    pub jsonl_exists: bool,
+    pub jsonl_newer: bool,
+    pub db_newer: bool,
