+/// Generate a realistic-looking issue title.
+fn generate_title(rng: &mut StdRng, index: usize) -> String {
+    let prefixes = [
+        "Add",
+        "Fix",
+        "Update",
+        "Refactor",
+        "Implement",
+        "Remove",
+        "Improve",
+        "Optimize",
+        "Document",
+        "Test",
+        "Review",
+        "Debug",
+        "Cleanup",
+        "Migrate",
+        "Configure",
+    ];
+
+    let subjects = [
+        "authentication flow",
+        "database connection",
+        "API endpoint",
+        "user interface",
+        "error handling",
+        "logging system",
+        "configuration",
+        "test coverage",
+        "documentation",
+        "performance",
+        "security",
+        "caching",
+        "validation",
+        "serialization",
+        "routing",
+    ];
+
+    let prefix = prefixes[rng.random_range(0..prefixes.len())];
+    let subject = subjects[rng.random_range(0..subjects.len())];
+
+    format!("{prefix} {subject} (#{index})")
+}
