+    } else {
+        MemoryStats { max_rss_kb: None }
+    };
+
+    let bd_create = workspace.run_bd(["create", "RSS close test bd", "--type", "task", "--json"]);
+    let bd_rss = if let Ok(v) = serde_json::from_str::<serde_json::Value>(&bd_create.stdout) {
